    17→
    18→	private readonly _proxy: ExtHostDiagnosticsShape;
    19→	private readonly _markerListener: IDisposable;
    20→
    21→	constructor(
    22→		extHostContext: IExtHostContext,
    23→		@IMarkerService private readonly _markerService: IMarkerService,
    24→		@IUriIdentityService private readonly _uriIdentService: IUriIdentityService,
    25→	) {
