// Test file to verify the implementation
import * as vscode from 'vscode';

// This test verifies that the diagnostics are cleared when files change
async function testFileChange() {
    // Simulated scenario: Git switches branches, file content changes
    console.log('Testing file change scenario...');

    // The implementation should:
    // 1. Detect file change via file watcher
    // 2. Clear stale diagnostics
